import heapq

def lastStoneWeight(stones: list[int]) -> int:
    max_heap = []
    for stone in stones:
        heapq.heappush(max_heap, -stone)  # Simulate max-heap by storing negative values

    while len(max_heap) > 1:
        y = -heapq.heappop(max_heap)  # Largest stone
        x = -heapq.heappop(max_heap)  # Second largest stone

        if y != x:
            new_stone = y - x
            heapq.heappush(max_heap, -new_stone)

    return -heapq.heappop(max_heap) if max_heap else 0
